const rows = $input.all();
const sinProcesar = rows.find(row => {
  const p = row.json.Procesado;
  return !p || p === false || p === null || p === undefined;
});
if (!sinProcesar) return [];
return [{ json: {
  ...sinProcesar.json,
  _airtable_id: sinProcesar.json.id
} }];

const trigger = $('Separar Jobs').item.json || {};
const vacante = $('Obtener Vacante').item.json || {};
const cv_text = $json.text || '';

const nombre = trigger['Nombre completo'] || '';
const jobPostulado = Array.isArray(trigger['Job (from Jobs)']) ? trigger['Job (from Jobs)'][0] : (trigger['Job (from Jobs)'] || '');
const cvLink = Array.isArray(trigger['CV']) ? (trigger['CV'][0]?.url || '') : (trigger['CV'] || '').toString();

const systemPrompt = `SISTEMA DE SCREENING AUTOMATICO DE CANDIDATOS

INFORMACION DEL CANDIDATO:
- Nombre: ${nombre}
- Email: ${trigger.Email || ''}
- LinkedIn: ${trigger.LinkedIn || 'No informado'}
- Puesto solicitado: ${jobPostulado}
- Skills principales: ${trigger['Skills principales'] || ''}
- Anios de experiencia declarados: ${trigger['Años de experiencia'] || ''}
- Seniority declarado: ${trigger.Seniority || ''}
- Ciudad: ${trigger.Ciudad || ''}, ${trigger.País || ''}
- Link del CV: ${cvLink}

CONTENIDO DEL CV:
${cv_text}

CRITERIOS DE LA VACANTE:
- Job ID: ${vacante.Job_ID || ''}
- Puesto: ${vacante.Job || ''}
- Departamento: ${vacante.Department || ''}
- Descripcion: ${vacante.Description || ''}
- Required Skills: ${vacante.Required_Skills || ''}
- Nice to Have: ${vacante.Nice_to_Have || ''}
- Seniority: ${vacante.Seniority || ''}
- Experiencia minima: ${vacante.Min_Years_Experience || 0} anios
- Ubicacion: ${vacante.Location || ''}
- Tipo: ${vacante.Employment_Type || ''}

INSTRUCCIONES:
1. Extrae del CV: anios de experiencia, skills, educacion, ubicacion
2. Compara contra los criterios de la vacante
3. Valida primero Required_Skills (no negociables)
4. Evalua Nice_to_Have como valor agregado
5. Detecta red flags: gaps >3 meses, cambios <6 meses, CV vago
6. Asigna puntuacion 0-100 y status final

ESCALA:
- 85-100: CUMPLE (todas las required skills + experiencia OK)
- 70-84: CUMPLE (required skills OK, falta algo de nice to have)
- 50-69: REVISAR (cumple parcialmente, tiene potencial)
- 0-49: NO CUMPLE (falta experiencia o mas de 1 required skill)

RESPONDE SOLO JSON VALIDO SIN MARKDOWN:
{
  "candidato": "",
  "email": "",
  "linkedin": "",
  "puesto_solicitado": "",
  "job_id": "",
  "cv_link": "",
  "puntuacion_total": 0,
  "status": "CUMPLE|REVISAR|NO CUMPLE",
  "experiencia": {"anos_requeridos": 0, "anos_encontrados": 0, "seniority_requerido": "", "seniority_encontrado": "", "rubro_relevante": true, "detalle": ""},
  "required_skills": {"total_requeridas": 0, "encontradas": [], "faltantes": [], "porcentaje_match": 0},
  "nice_to_have": {"encontradas": [], "faltantes": []},
  "ubicacion": {"requerida": "", "candidato": "", "cumple": true},
  "fortalezas": [],
  "debilidades": [],
  "red_flags": [],
  "resumen_ejecutivo": "",
  "motivo_status": "",
  "proximo_paso": ""
}`;

return [{
  json: {
    requestBody: {
      model: 'claude-opus-4-5',
      max_tokens: 2048,
      system: systemPrompt,
      messages: [{ role: 'user', content: 'Analiza el CV y devuelve el JSON del analisis.' }]
    },
    recruiter: (() => { const r = vacante.Recruiter; if (!r) return ''; if (Array.isArray(r)) return r[0]?.name || r[0]?.email || ''; if (typeof r === 'object') return r.name || r.email || ''; return r; })(),
    slack_channel: vacante.Slack_Channel || '',
    job_id: vacante.Job_ID || '',
    job: vacante.Job || '',
    airtable_record_id: trigger._airtable_id || '',
    cv_link: cvLink
  }
}];

const promptNode = $('Preparar Prompt').item.json;
let parsed;
try {
  const responseText = $json.content[0].text;
  const cleanJson = responseText.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleanJson);
} catch (e) {
  throw new Error(`Claude no devolvio JSON valido: ${e.message}`);
}
return [{
  json: {
    ...parsed,
    recruiter: promptNode.recruiter,
    slack_channel: promptNode.slack_channel,
    airtable_record_id: promptNode.airtable_record_id
  }
}];

const candidato = $input.first().json;
const jobs = Array.isArray(candidato.Jobs) 
  ? candidato.Jobs 
  : (candidato.Jobs ? [candidato.Jobs] : []);
const jobNames = Array.isArray(candidato['Job (from Jobs)']) 
  ? candidato['Job (from Jobs)'] 
  : (candidato['Job (from Jobs)'] ? [candidato['Job (from Jobs)']] : []);

if (jobs.length === 0) return [];

return jobs.map((jobId, index) => ({
  json: {
    ...candidato,
    Jobs: [jobId],
    'Job (from Jobs)': jobNames[index] !== undefined 
      ? [jobNames[index]] 
      : [jobNames[0] || '']
  }
}));
